import faiss
from langchain import OpenAI, VectorDBQA
from langchain.embeddings.openai import OpenAIEmbeddings
from langchain.vectorstores.faiss import FAISS

# Load company documents into vector database
def load_documents_into_vector_db(documents):
    embeddings = OpenAIEmbeddings()
    vector_store = FAISS.from_texts(documents, embeddings)
    return vector_store

# Create RAG system
def create_rag_system(vector_store):
    llm = OpenAI(temperature=0)
    rag_system = VectorDBQA(llm=llm, chain_type="stuff", vectorstore=vector_store)
    return rag_system

# Accept user queries and retrieve relevant context
def get_relevant_context(rag_system, query):
    result = rag_system.run(query)
    return result

# Example usage
if __name__ == "__main__":
    # Sample documents (replace with actual company documents)
    documents = [
        "Alibaba Cloud is a subsidiary of Alibaba Group.",
        "OpenAI develops artificial intelligence technologies.",
        "LangChain is an open-source framework for building language models."
    ]

    # Load documents into vector database
    vector_store = load_documents_into_vector_db(documents)

    # Create RAG system
    rag_system = create_rag_system(vector_store)

    # Accept user query
    user_query = input("Enter your query: ")

    # Retrieve relevant context
    response = get_relevant_context(rag_system, user_query)
    print("Response:", response)